import './Layout.scss';
import AboutMe from './AboutMe';
import Experience from './Experience';

function Layout({menuType}) {
    return (
        <div className="Layout">
            <hidden>
                <AboutMe></AboutMe>
            </hidden>
            <hidden>
                <Experience></Experience>
            </hidden>
        </div>
    );
}

export default Layout;
